-- TMT 2026-05-27 dueña: 'historicos sin conciliar no son 800, son aprox 175 lineas'.
-- Mi parser anterior leía Hoja1/2/5 (fechas datetime) y SALTÓ FEB2023
-- (fechas string). FEB2023 tiene los pendientes ACTUALES.
-- Estas son las 173 filas reales con NET = $198,650.34.

BEGIN;

-- 1) Borrar las filas mal cargadas de migracion 0055 (hojas viejas Hoja1/2/5).
DELETE FROM scintela.banco_historicos_pendientes
 WHERE no_banco = 10
   AND creado_por = 'tamara-carga-inicial'
   AND (fuente LIKE 'xlsx:Hoja%' OR fuente LIKE 'xlsx:FEB%');

-- 2) Cargar las 173 de FEB2023 (xlsx CONCILIACION_ENERO_2026).
ON CONFLICT (no_banco, fecha, COALESCE(documento, ''), monto, tipo) DO NOTHING;

COMMIT;
